#!/usr/bin/env node
// Quality Scorecard — honest self-assessment of how submission-ready the project is.
// Used by awesome-list maintainers to judge new submissions. Run before submitting PRs.

import { existsSync, readFileSync, writeFileSync, mkdirSync } from 'node:fs';
import { execSync } from 'node:child_process';
import { dirname } from 'node:path';

const REPO = process.env.REPO || 'theihtisham/agent-shadow-brain';
const REPORT_PATH = 'docs/QUALITY_SCORECARD.md';

const checks = [];
function check(name, ok, detail = '') {
  checks.push({ name, ok, detail });
}

// 1. Core community files (most awesome lists require these)
check('README.md exists', existsSync('README.md'));
check('LICENSE file', existsSync('LICENSE') || existsSync('LICENSE.md'));
check('CHANGELOG.md', existsSync('CHANGELOG.md'));
check('CONTRIBUTING.md', existsSync('CONTRIBUTING.md'));
check('CODE_OF_CONDUCT.md', existsSync('CODE_OF_CONDUCT.md'));
check('SECURITY.md', existsSync('SECURITY.md'));

// 2. GitHub-specific
check('.github/ISSUE_TEMPLATE exists', existsSync('.github/ISSUE_TEMPLATE'));
check('.github/PULL_REQUEST_TEMPLATE.md', existsSync('.github/PULL_REQUEST_TEMPLATE.md'));
check('.github/FUNDING.yml', existsSync('.github/FUNDING.yml'));
check('.github/workflows (CI)', existsSync('.github/workflows'));

// 3. Code quality signals
check('package.json', existsSync('package.json'));
check('tsconfig.json (typed)', existsSync('tsconfig.json'));
check('Tests directory', existsSync('tests') || existsSync('__tests__') || existsSync('test'));
check('.gitignore', existsSync('.gitignore'));

// 4. Project metadata (via gh API)
let meta = {};
try {
  meta = JSON.parse(execSync(`gh api repos/${REPO}`, { encoding: 'utf-8' }));
} catch {}

const stars = meta.stargazers_count ?? 0;
const description = meta.description ?? '';
const topics = meta.topics ?? [];
const homepage = meta.homepage ?? '';
const hasWiki = meta.has_wiki ?? false;
const hasDiscussions = meta.has_discussions ?? false;

check('Description set on GitHub', description.length > 20, `${description.length} chars`);
check('At least 5 topics set', topics.length >= 5, `${topics.length} topics`);
check('Description has main keyword', /agent|brain|shadow|ai/i.test(description));
check('Homepage URL set', homepage.length > 0, homepage || 'none');
check('Discussions enabled', hasDiscussions);
check('At least 100 stars (most awesome-list floor)', stars >= 100, `${stars} stars`);
check('At least 10 stars (lowest floor)', stars >= 10, `${stars} stars`);

// 5. README quality (parse README)
let readme = '';
if (existsSync('README.md')) {
  readme = readFileSync('README.md', 'utf-8');
}

check('README has install instructions', /npm install|npx|yarn add|pnpm add/i.test(readme));
check('README has badges (top of file)', readme.slice(0, 2000).includes('![') || readme.slice(0, 2000).includes('[!['));
check('README has demo / example', /example|demo|usage|getting started|quick start/i.test(readme));
check('README has features list', /features|capabilities|what it does/i.test(readme));
check('README first 200 chars are punchy', readme.replace(/^#.*?\n/, '').trim().slice(0, 200).split(/\s+/).length > 20);

// 6. npm package quality (if applicable)
let pkg = {};
if (existsSync('package.json')) {
  try { pkg = JSON.parse(readFileSync('package.json', 'utf-8')); } catch {}
}

check('package.json description', (pkg.description ?? '').length > 50);
check('package.json keywords (>=10)', (pkg.keywords ?? []).length >= 10);
check('package.json repository', !!pkg.repository);
check('package.json bugs URL', !!pkg.bugs);
check('package.json license', !!pkg.license);

// 7. CI status
let ciStatus = 'unknown';
try {
  const runs = JSON.parse(execSync(`gh api repos/${REPO}/actions/runs?per_page=1 --jq '.workflow_runs[0]'`, { encoding: 'utf-8' }));
  ciStatus = runs?.conclusion ?? 'unknown';
} catch {}
check('Latest CI run successful', ciStatus === 'success', `last: ${ciStatus}`);

// Score calculation
const passed = checks.filter(c => c.ok).length;
const total = checks.length;
const pct = Math.round((passed / total) * 100);

const grade = pct >= 95 ? 'A+' : pct >= 90 ? 'A' : pct >= 80 ? 'B' : pct >= 70 ? 'C' : pct >= 60 ? 'D' : 'F';

const md = `# Quality Scorecard

_Auto-generated by the Viral Amplifier Bot. Last refresh: ${new Date().toISOString().slice(0, 10)}._

## Overall Score: **${passed}/${total}** (${pct}%) — Grade **${grade}**

${pct >= 90 ? '✅ Submission-ready for most awesome lists.' : pct >= 75 ? '⚠️ Mostly ready — fix the failed items below before submitting.' : '❌ Not yet ready for high-traffic awesome lists. Address failures first.'}

## Checks

| # | Check | Status | Detail |
|---|---|:---:|---|
${checks.map((c, i) => `| ${i + 1} | ${c.name} | ${c.ok ? '✅' : '❌'} | ${c.detail} |`).join('\n')}

## Failed Items (in priority order)

${checks.filter(c => !c.ok).map(c => `- ❌ **${c.name}** ${c.detail ? `— ${c.detail}` : ''}`).join('\n') || '_None — everything passes!_'}

---

## How Awesome-List Maintainers Judge Submissions

Most maintainers use a checklist similar to:

1. ✅ Project has clear, descriptive README
2. ✅ Project has been actively maintained in last 6 months
3. ✅ Project has ≥100 GitHub stars (varies by list)
4. ✅ Project has CONTRIBUTING.md and CODE_OF_CONDUCT.md
5. ✅ Project has automated tests + passing CI
6. ✅ Project description is specific (not generic marketing)
7. ✅ Project URL is canonical (not redirect)
8. ✅ Project license is permissive (MIT, Apache, BSD)
9. ✅ Submission PR follows the list's CONTRIBUTING.md exactly

If your scorecard is below 80%, fix that before submitting — rejected PRs hurt your sender reputation.

## Auto-Generated Improvements

To get to 100%, generate missing community files via:

\`\`\`bash
node .github/scripts/generate-community-files.mjs
\`\`\`

This creates CONTRIBUTING.md, CODE_OF_CONDUCT.md, SECURITY.md, issue templates, and PR template if any are missing.
`;

mkdirSync(dirname(REPORT_PATH), { recursive: true });
writeFileSync(REPORT_PATH, md);
console.log(`Quality scorecard: ${passed}/${total} (${pct}%) — Grade ${grade}`);
console.log(`Report written to ${REPORT_PATH}`);

// Exit with non-zero if score is too low (CI gate option)
if (process.env.STRICT === '1' && pct < 80) {
  console.error(`Quality score ${pct}% is below 80% threshold.`);
  process.exit(1);
}
